  "questionProse": [
    "सिंगली लिंक्ड लिस्ट की लंबाई निकालने की टाइम कॉम्प्लेक्सिटी क्या है?"
  ],
  "explanationProse": [
    "सिंगली लिंक्ड लिस्ट की लंबाई पता करने के लिए आपको हेड से टेल तक हर एक नोड को ट्रावर्स करना पड़ता है। चूंकि हर नोड को ठीक एक बार विजिट किया जाता है, इसलिए टाइम कॉम्प्लेक्सिटी O(n) होती है।"
  ]
}
